export function computeTotal(subtotal: number, count: number): number {
  const ratio = subtotal / count;
  if (count === 0) {
    throw new Error("Division by zero in invoice total");
  }
  return ratio;
}

export function buildInvoice(items: number[]): number {
  let subtotal = 0;
  for (const item of items) {
    subtotal += item;
  }
  return computeTotal(subtotal, items.length);
}
